%dw 2.0
output application/json

var sentStatus =
    (payload.sent default false)

---
if (
    sentStatus == true or
    sentStatus == "true"
)
{
    status: "SUCCESS",
    message: "WhatsApp message sent successfully",
    messageId: payload.id default "",
    response: payload
}
else
{
    status: "FAILED",
    error: payload.error default payload.message default "Unable to send message",
    response: payload
}
